solution.bands.py:
"""Map a numeric score to a letter band."""


def band(score):
    if score >= 90:
        return "A"
    if score >= 80:
        return "B"
    if score >= 70:
        return "C"
    return "D"

solution.qty.py:
"""Parse quantity strings like "3" or "12"."""


def parse_qty(text):
    text = text.strip()
    if not text.isdigit():
        raise ValueError("not a quantity: " + text)
    return int(text)

solution.settings.py:
