solution.rows.py:
"""Sum the amount column of parsed CSV rows."""


def parse_row(line):
    name, amount = line.split(",")
    return {"name": name.strip(), "amount": int(amount.strip())}


def total_amount(rows):
    total = 0
    for row in rows:
        total += row["amount"]
    return total

